#!/bin/bash
set -euo pipefail

# ═══════════════════════════════════════════════════════════════════
# Life Platform — Deploy Pixel Art Sprites + Frontend Updates
# v2.65.0: Replace SVG placeholders with PNG pixel art sprites
# ═══════════════════════════════════════════════════════════════════

BUCKET="matthew-life-platform"
DASH_DIST="E1QKQNXVBZPGF0"
BUDDY_DIST="E2DLDWDOIHZXZ8"
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
STAGE=0
TOTAL=5

pass() { STAGE=$((STAGE+1)); echo ""; echo "✅ [$STAGE/$TOTAL] $1"; }
fail() { echo "❌ FAILED at step $STAGE: $1"; exit 1; }

echo "═══════════════════════════════════════════════════════"
echo "  Life Platform — Pixel Art Sprite Deploy (v2.65.0)"
echo "═══════════════════════════════════════════════════════"
echo ""

# --- Step 1: Extract embedded sprites ---
pass "Extracting 48 pixel art sprites..."
TMPDIR=$(mktemp -d)
SPRITE_B64=""

echo "$SPRITE_B64" | base64 -d | tar xzf - -C "$TMPDIR"
echo "  Extracted to $TMPDIR"
echo "  base/:    $(ls "$TMPDIR/base/" | wc -l) sprites"
echo "  badges/:  $(ls "$TMPDIR/badges/" | wc -l) sprites"
echo "  effects/: $(ls "$TMPDIR/effects/" | wc -l) sprites"
echo "  crown/:   $(ls "$TMPDIR/crown/" | wc -l) sprites"
echo "  email/:   $(ls "$TMPDIR/email/" | wc -l) sprites"

# --- Step 2: Upload sprites to S3 ---
pass "Uploading sprites to S3 (dashboard/avatar/)..."
aws s3 sync "$TMPDIR/" "s3://$BUCKET/dashboard/avatar/" \
  --content-type "image/png" \
  --cache-control "public, max-age=86400" \
  --delete \
  || fail "S3 sprite upload"
echo "  Uploaded to s3://$BUCKET/dashboard/avatar/"

# --- Step 3: Upload updated dashboard HTML ---
pass "Uploading dashboard index.html (PNG sprite renderer)..."
aws s3 cp "$ROOT/lambdas/dashboard/index.html" \
  "s3://$BUCKET/dashboard/index.html" \
  --content-type "text/html" \
  --cache-control "no-cache" \
  || fail "Dashboard HTML upload"
DASH_SIZE=$(aws s3api head-object --bucket "$BUCKET" --key "dashboard/index.html" --query 'ContentLength' --output text 2>/dev/null)
echo "  dashboard/index.html: ${DASH_SIZE} bytes"

# --- Step 4: Upload updated buddy page HTML ---
pass "Uploading buddy page index.html (PNG sprite renderer)..."
aws s3 cp "$ROOT/lambdas/buddy/index.html" \
  "s3://$BUCKET/buddy/index.html" \
  --content-type "text/html" \
  --cache-control "no-cache" \
  || fail "Buddy HTML upload"
BUDDY_SIZE=$(aws s3api head-object --bucket "$BUCKET" --key "buddy/index.html" --query 'ContentLength' --output text 2>/dev/null)
echo "  buddy/index.html: ${BUDDY_SIZE} bytes"

# --- Step 5: CloudFront invalidation ---
pass "Invalidating CloudFront caches..."
DASH_INV=$(aws cloudfront create-invalidation \
  --distribution-id "$DASH_DIST" \
  --paths "/dashboard/*" "/dashboard/avatar/*" \
  --query 'Invalidation.Id' --output text 2>/dev/null)
echo "  Dashboard invalidation: $DASH_INV"

BUDDY_INV=$(aws cloudfront create-invalidation \
  --distribution-id "$BUDDY_DIST" \
  --paths "/buddy/*" \
  --query 'Invalidation.Id' --output text 2>/dev/null)
echo "  Buddy invalidation: $BUDDY_INV"

# Cleanup
rm -rf "$TMPDIR"

echo ""
echo "═══════════════════════════════════════════════════════"
echo "  ✅ Deploy complete — v2.65.0 Pixel Art Sprites"
echo "═══════════════════════════════════════════════════════"
echo ""
echo "  48 PNG sprites uploaded to dashboard/avatar/"
echo "  Dashboard: SVG → PNG sprite renderer"
echo "  Buddy:     SVG → PNG sprite renderer (cross-origin from dash)"
echo ""
echo "  Verify:"
echo "    https://dash.averagejoematt.com"
echo "    https://buddy.averagejoematt.com"
echo ""
echo "  Sprite paths: dashboard/avatar/base/{tier}-frame{frame}.png"
echo "  To update a sprite later:"
echo "    aws s3 cp new.png s3://$BUCKET/dashboard/avatar/base/foundation-frame1.png"
echo "    aws cloudfront create-invalidation --distribution-id $DASH_DIST --paths '/dashboard/avatar/*'"
echo ""
